  `drawn_at` datetime NOT NULL COMMENT '추첨 시각',
  `created_at` datetime DEFAULT current_timestamp() COMMENT '레코드 생성 시각',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_round` (`round`),
  KEY `idx_drawn_at` (`drawn_at`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=452 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='추첨 결과 (5분 주기)';

